// src/components/TelaCaixas.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'

export default function TelaCaixas() {
  const [caixas, setCaixas] = useState([])
  const [nome, setNome] = useState('')
  const [codigo, setCodigo] = useState('')
  const [editingId, setEditingId] = useState(null)

  useEffect(() => {
    fetchCaixas()
  }, [])

  async function fetchCaixas() {
    try {
      const { data } = await axios.get('/api/caixas')
      setCaixas(data)
    } catch (err) {
      console.error(err)
    }
  }

  async function handleSubmit(e) {
    e.preventDefault()
    try {
      if (editingId) {
        await axios.put(`/api/caixas/${editingId}`, {
          nome,
          codigo_barras: codigo
        })
      } else {
        await axios.post('/api/caixas', {
          nome,
          codigo_barras: codigo
        })
      }
      setNome('')
      setCodigo('')
      setEditingId(null)
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert(editingId ? 'Erro ao atualizar caixa' : 'Erro ao cadastrar caixa')
    }
  }

  function handleEdit(c) {
    setEditingId(c.id)
    setNome(c.nome)
    setCodigo(c.codigo_barras)
  }

  async function handleDelete(id) {
    if (!window.confirm('Tem certeza que deseja excluir esta caixa?')) return
    try {
      await axios.delete(`/api/caixas/${id}`)
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert('Erro ao excluir caixa')
    }
  }

  function handleCancel() {
    setEditingId(null)
    setNome('')
    setCodigo('')
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Gerenciar Caixas</h2>

      {/* formulário em card */}
      <div className="bg-white rounded-2xl shadow p-6">
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <input
            className="col-span-1 md:col-span-2 w-full border rounded px-3 py-2"
            placeholder="Nome da Caixa"
            value={nome}
            onChange={e => setNome(e.target.value)}
            required
          />
          <input
            className="w-full border rounded px-3 py-2"
            placeholder="Código de Barras"
            value={codigo}
            onChange={e => setCodigo(e.target.value)}
            required
          />
          <div className="flex gap-2">
            <button
              type="submit"
              className="h-fit self-end bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-full"
            >
              {editingId ? 'Atualizar' : 'Cadastrar'}
            </button>
            {editingId && (
              <button
                type="button"
                onClick={handleCancel}
                className="h-fit self-end bg-gray-400 hover:bg-gray-500 text-white font-bold px-4 py-2 rounded-full"
              >
                Cancelar
              </button>
            )}
          </div>
        </form>
      </div>

      {/* lista de caixas em cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {caixas.map(c => (
          <div
            key={c.id}
            className="bg-white rounded-2xl shadow p-6 flex flex-col justify-between"
          >
            <div className="space-y-1">
              <p><span className="font-medium">ID:</span> {c.id}</p>
              <p><span className="font-medium">Nome:</span> {c.nome}</p>
              <p><span className="font-medium">Código:</span> {c.codigo_barras}</p>
            </div>
            <div className="mt-4 flex gap-2">
              <button
                onClick={() => handleEdit(c)}
                className="flex-1 bg-yellow-500 hover:bg-yellow-600 text-white px-3 py-2 rounded-full text-sm"
              >
                Editar
              </button>
              <button
                onClick={() => handleDelete(c.id)}
                className="flex-1 bg-red-600 hover:bg-red-700 text-white px-3 py-2 rounded-full text-sm"
              >
                Excluir
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}
